import { Component, Host, Listen, Prop, State, h } from '@stencil/core';
import { FD_TYPES } from '../../../../services/city-ledger';
import type { ClFiscalDocumentPreviewRequest } from './types';

@Component({
  tag: 'ir-cl-fiscal-document-preview',
  shadow: false,
})
export class IrClFiscalDocumentPreview {
  @Prop() ticket: string;
  @Prop() propertyId: number;

  @State() request: ClFiscalDocumentPreviewRequest | null = null;

  @Listen('clFiscalDocumentPreview', { target: 'window' })
  handlePreviewRequest(event: CustomEvent<ClFiscalDocumentPreviewRequest>) {
    this.request = { ...event.detail };
    if (event.detail.autoPrint) {
      window.print();
    }
  }

  private getDialogLabel(): string {
    if (!this.request) return 'Preview';
    return `${this.getTypeLabel(this.request.fdTypeCode)} — ${this.request.documentNumber}`;
  }

  private getTypeLabel(fdTypeCode: string): string {
    switch (fdTypeCode) {
      case FD_TYPES.Invoice:
      case FD_TYPES.Draft:
        return 'Invoice Preview';
      case FD_TYPES.CreditNote:
        return 'Credit Note Preview';
      case FD_TYPES.DebitNote:
        return 'Debit Note Preview';
      case FD_TYPES.Receipt:
        return 'Receipt Preview';
      default:
        return 'Document Preview';
    }
  }

  private renderPreview() {
    if (!this.request) return null;
    const { fdTypeCode, documentNumber, agentId, agentName } = this.request;
    const commonProps = {
      ticket: this.ticket,
      propertyId: this.propertyId,
      agentId,
      agentName,
      documentNumber,
    };

    switch (fdTypeCode) {
      case FD_TYPES.Invoice:
      case FD_TYPES.Draft:
        return <ir-cl-invoice-preview {...commonProps}></ir-cl-invoice-preview>;
      case FD_TYPES.CreditNote:
        return <ir-cl-credit-note-preview {...commonProps}></ir-cl-credit-note-preview>;
      case FD_TYPES.DebitNote:
        return <ir-cl-debit-note-preview {...commonProps}></ir-cl-debit-note-preview>;
      case FD_TYPES.Receipt:
        return <ir-cl-receipt-preview {...commonProps}></ir-cl-receipt-preview>;
      default:
        return <ir-cl-invoice-preview {...commonProps}></ir-cl-invoice-preview>;
    }
  }

  render() {
    return (
      <Host>
        <ir-preview-screen-dialog
          open={this.request !== null}
          label={this.getDialogLabel()}
          action="print"
          onOpenChanged={e => {
            if (!e.detail) this.request = null;
          }}
        >
          {this.renderPreview()}
        </ir-preview-screen-dialog>
      </Host>
    );
  }
}
